// TestPreClaimWarnAlternatingFingerprintsBelowThresholdDoNotEscalate verifies
// that alternating/differing pre-claim warn fingerprints do NOT trigger
// escalation, and the loop continues draining normally. Each distinct
// fingerprint resets the counter.
func TestPreClaimWarnAlternatingFingerprintsBelowThresholdDoNotEscalate(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())
	beadIDs := []string{
		"ddx-alternating-warn-1",
		"ddx-alternating-warn-2",
		"ddx-alternating-warn-3",
		"ddx-alternating-warn-4",
		"ddx-alternating-warn-5",
	}
	for i, beadID := range beadIDs {
		require.NoError(t, store.Create(&bead.Bead{
			ID:       beadID,
			Title:    "alternating warn bead " + beadID,
			Priority: i,
		}))
	}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				ResultRev: "rev-" + beadID,
			}, nil
		}),
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	var eventSink, logBuf bytes.Buffer
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	callCount := 0
	result, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:                        executeloop.ModeDrain,
		Log:                         &logBuf,
		EventSink:                   &eventSink,
		NoReview:                    true,
		PreClaimWarnRepeatThreshold: DefaultPreClaimWarnRepeatThreshold,
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
			callCount++
			var reason string
			if callCount%2 == 0 {
				reason = "alternating_error_A"
			} else {
				reason = "alternating_error_B"
			}
			return PreClaimIntakeResult{
				Outcome: PreClaimIntakeError,
				Reason:  reason,
				Detail:  "alternating detail for " + reason,
			}, nil
		},
	})

	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, len(beadIDs), result.Attempts, "all beads must be processed with alternating fingerprints")
	assert.Equal(t, len(beadIDs), result.Successes, "all beads must succeed despite alternating warns")
	assert.Equal(t, 0, result.Failures)
	assert.Nil(t, result.OperatorAttention, "alternating fingerprints must not trigger escalation")

	for _, beadID := range beadIDs {
		got, err := store.Get(beadID)
		require.NoError(t, err)
		assert.Equal(t, bead.StatusClosed, got.Status)
	}

	lines := strings.Split(strings.TrimSpace(eventSink.String()), "\n")
	var escalations []map[string]any
	for _, line := range lines {
		if strings.TrimSpace(line) == "" {
			continue
		}
		var entry map[string]any
		require.NoError(t, json.Unmarshal([]byte(line), &entry))
		if entry["type"] != "loop.operator_attention" {
			continue
		}
		data, ok := entry["data"].(map[string]any)
		require.True(t, ok)
		if data["reason"] == "preclaim_warn_repeated" {
			escalations = append(escalations, data)
		}
	}
	require.Len(t, escalations, 0, "alternating fingerprints must not trigger escalation")
}

